<template>
  <div class="screen-container">
    <div class="screen-scale" :style="scaleStyle">
      <ScreenHeader title="职业技能等级认定实操考试" />
      <section class="screen-main">
        <div class="screen-table-header">
          <div class="header-cell c0">教室</div>
          <div class="header-cell c1">职业（工种）</div>
          <div class="header-cell c2">级别</div>
          <div class="header-cell c3">正在考试</div>
          <div class="header-cell c4">准备考试</div>
          <div class="header-cell c5">已过号</div>
        </div>
        <div class="middle-chart">
          <div class="table-body-viewport">
            <div class="table-body-track" :style="trackStyle">
              <div v-for="(row, i) in renderedRows" :key="i" class="table-row" :style="{
                ...rowStyle,
                background: row.rowBg || '#ffffff',
              }">
                <template v-if="row._placeholder">
                  <div class="placeholder-cell"></div>
                </template>
                <template v-else>
                  <div class="body-cell c0 body-cell-center body-cell-blue">
                    <span class="text-ellipsis">{{ row.room || "" }}</span>
                  </div>
                  <div class="body-cell c1 body-cell-dark">
                    <span class="text-ellipsis">{{ row.job || "" }}</span>
                  </div>
                  <div class="body-cell c2 body-cell-center body-cell-blue">
                    <span class="text-ellipsis">{{ row.level || "" }}</span>
                  </div>
                  <div class="body-cell c3 body-cell-dark">
                    <div class="marquee-wrap">
                      <div class="marquee-track" :data-marquee-enabled="needsMarquee(testingText(row.testing), 'testing')
                          ? '1'
                          : '0'
                        " :data-marquee-cycle="marqueeCycle(testingText(row.testing), 'testing')
                          ">
                        <span class="marquee-item" :class="{
                          'text-danger':
                            testingText(row.testing) === '未开始',
                        }">{{ testingText(row.testing) }}</span>
                        <span v-if="
                          needsMarquee(testingText(row.testing), 'testing')
                        " class="marquee-item" :class="{
                            'text-danger':
                              testingText(row.testing) === '未开始',
                          }">{{ testingText(row.testing) }}</span>
                      </div>
                    </div>
                  </div>
                  <div class="body-cell c4 body-cell-blue">
                    <div class="marquee-wrap">
                      <div class="marquee-track" :data-marquee-enabled="needsMarquee(joinText(row.waiting), 'waiting')
                          ? '1'
                          : '0'
                        " :data-marquee-cycle="marqueeCycle(joinText(row.waiting), 'waiting')
                          ">
                        <span class="marquee-item">{{
                            joinText(row.waiting)
                          }}</span>
                        <span v-if="needsMarquee(joinText(row.waiting), 'waiting')" class="marquee-item">{{
                            joinText(row.waiting) }}</span>
                      </div>
                    </div>
                  </div>
                  <div class="body-cell c5 body-cell-passed">
                    <span class="passed-prefix">{{
                        (row.passed && row.passed.prefix) || ""
                      }}</span>
                    <div class="passed-users marquee-wrap">
                      <div class="marquee-track" :data-marquee-enabled="needsMarquee(
                        joinText(row.passed && row.passed.users),
                        'passed'
                      )
                          ? '1'
                          : '0'
                        " :data-marquee-cycle="marqueeCycle(
                          joinText(row.passed && row.passed.users),
                          'passed'
                        )
                          ">
                        <span class="marquee-item text-success">{{
                            joinText(row.passed && row.passed.users)
                          }}</span>
                        <span v-if="
                          needsMarquee(
                            joinText(row.passed && row.passed.users),
                            'passed'
                          )
                        " class="marquee-item text-success">{{ joinText(row.passed && row.passed.users) }}</span>
                      </div>
                    </div>
                  </div>
                </template>
              </div>
            </div>
          </div>
        </div>
      </section>
      <footer class="screen-footer">
        <span class="tip-label">温馨提示：请等待叫号依次参加实操考试，</span>
        <span class="tip-text">若已过号请等待重新叫号</span>
      </footer>
      <div v-if="isTouchDevice && !userGestureUnlocked" class="sound-unlock-mask" @click="tryUnlockAudio">
        <div class="sound-unlock-card">
          <div class="sound-unlock-title">点击开启语音播报</div>
          <div class="sound-unlock-sub">
            手机浏览器通常需要手动点击后才允许播放声音/语音
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { getTheoryexaminationQueue } from "@/api/screen/screen";
import ScreenHeader from "./screenTop.vue";
export default {
  name: "ScreenIndex",
  components: {
    ScreenHeader,
  },
  data() {
    return {
      designWidth: 2200,
      designHeight: 1090,
      scale: 1,
      offsetX: 0,
      offsetY: 0,
      frameRafId: null,
      marqueeBaseTime: 0,
      marqueeSpeed: 60,
      lastFrameTime: 0,
      vScrollMode: "",
      vScrollPhaseStart: 0,
      vHoldMs: 5000,
      vMoveMs: 1000,
      visibleRowCount: 6,
      scrollRowIndex: 0,
      scrollProgress: 0,
      pollIntervalMs: 5000,
      pollTimerId: null,
      fetching: false,
      lastDataSignature: "",
      userGestureUnlocked: false,
      isTouchDevice: false,
      lastRowsForDiff: null,
      ttsQueue: [],
      ttsSpeaking: false,
      ttsLang: "zh-CN",
      ttsRate: 0.8,
      ttsPitch: 1,
      examRows: [],
      // examRows: [
      //   {
      //     room: "第一教室",
      //     job: "养老护理员",
      //     level: "五级",
      //     rowBg: "",
      //     testing: ["王建军", "张晓宇", "李国强", "陈志远"],
      //     waiting: ["马冬梅", "赵子豪", "刘思远", "周雨晴"],
      //     passed: {
      //       prefix: "候5位",
      //       users: ["孙浩然", "张晓宇", "马冬梅", "林子墨", "吴彦祖"],
      //     },
      //   }
      // ],
    };
  },
  computed: {
    scaleStyle() {
      return {
        width: `${this.designWidth}px`,
        height: `${this.designHeight}px`,
        transform: `scale(${this.scale})`,
        left: `${this.offsetX}px`,
        top: `${this.offsetY}px`,
      };
    },
    needsVerticalScroll() {
      return this.examRows.length > this.visibleRowCount;
    },
    renderedRows() {
      if (this.examRows.length < this.visibleRowCount) {
        const rows = this.examRows.map((row, index) => {
          const rowBg =
              row && row.rowBg
                  ? row.rowBg
                  : index % 2 === 1
                      ? "#D0E6F9"
                      : "#ffffff";
          return {
            ...row,
            rowBg,
            _sourceIndex: index,
          };
        });
        const missing = this.visibleRowCount - rows.length;
        for (let i = 0; i < missing; i++) {
          rows.push({
            _placeholder: true,
            rowBg: "#ffffff",
            _sourceIndex: rows.length,
          });
        }
        return rows;
      }
      if (!this.needsVerticalScroll) {
        return this.examRows.map((row, index) => {
          const rowBg =
              row && row.rowBg
                  ? row.rowBg
                  : index % 2 === 1
                      ? "#D0E6F9"
                      : "#ffffff";
          return {
            ...row,
            rowBg,
            _sourceIndex: index,
          };
        });
      }
      const count = this.visibleRowCount + 1;
      const rows = [];
      for (let i = 0; i < count; i++) {
        const sourceIndex = (this.scrollRowIndex + i) % this.examRows.length;
        const sourceRow = this.examRows[sourceIndex] || {};
        const rowBg =
            sourceRow && sourceRow.rowBg
                ? sourceRow.rowBg
                : sourceIndex % 2 === 1
                    ? "#D0E6F9"
                    : "#ffffff";
        rows.push({
          ...sourceRow,
          rowBg,
          _sourceIndex: sourceIndex,
        });
      }
      return rows;
    },
    rowStyle() {
      return {
        height: `${100 / this.visibleRowCount}%`,
      };
    },
    trackStyle() {
      if (!this.needsVerticalScroll) {
        return { transform: "translateY(0%)" };
      }
      return {
        transform: `translateY(-${(100 / this.visibleRowCount) * this.scrollProgress
        }%)`,
      };
    },
  },
  methods: {
    stableStringify(value) {
      if (value === undefined) return "null";
      if (value === null) return "null";
      const t = typeof value;
      if (t !== "object") return JSON.stringify(value);
      if (Array.isArray(value)) {
        return `[${value.map((v) => this.stableStringify(v)).join(",")}]`;
      }
      const keys = Object.keys(value).sort();
      return `{${keys
          .map((k) => `${JSON.stringify(k)}:${this.stableStringify(value[k])}`)
          .join(",")}}`;
    },
    tryUnlockAudio() {
      this.userGestureUnlocked = true;
    },
    normalizeNameList(list) {
      if (!Array.isArray(list)) return [];
      return list
          .map((t) => (t === null || t === undefined ? "" : String(t)).trim())
          .filter(Boolean);
    },
    normalizeRoomName(room) {
      const text =
          room === null || room === undefined ? "" : String(room).trim();
      if (!text) return "";
      if (text.includes("教室") || text.includes("考场")) return text;
      return `${text}教室`;
    },
    buildAnnouncements(prevRows, nextRows) {
      const prev = Array.isArray(prevRows) ? prevRows : [];
      const next = Array.isArray(nextRows) ? nextRows : [];
      const prevByRoom = new Map();
      prev.forEach((r) => {
        const key = (r && r.room) || "";
        if (!prevByRoom.has(key)) prevByRoom.set(key, r || {});
      });

      const messages = [];
      next.forEach((row) => {
        const key = (row && row.room) || "";
        const prevRow = prevByRoom.get(key) || {};

        // 播报新增的正在考试人员
        const prevTesting = this.normalizeNameList(prevRow.testing);
        const nextTesting = this.normalizeNameList(row && row.testing);
        const addedTesting = nextTesting.filter(
            (name) => !prevTesting.includes(name)
        );
        addedTesting.forEach((name) => {
          const room = this.normalizeRoomName((row && row.room) || "");
          if (room) messages.push(`请${name}同学 到 ${room} 进行考试`);
          else messages.push(`${name}到指定教室`);
        });

        // 播报新增的准备考试(waiting)人员
        const prevWaiting = this.normalizeNameList(prevRow.waiting);
        const nextWaiting = this.normalizeNameList(row && row.waiting);
        const addedWaiting = nextWaiting.filter(
            (name) => !prevWaiting.includes(name)
        );
        addedWaiting.forEach((name) => {
          messages.push(`请${name}提前做好准备，等待考试`);
        });
      });
      return messages;
    },
    speakMessages(messages) {
      if (this.isTouchDevice && !this.userGestureUnlocked) return false;
      if (typeof window === "undefined") return false;
      if (
          !window.speechSynthesis ||
          typeof window.SpeechSynthesisUtterance !== "function"
      )
        return false;
      const list = Array.isArray(messages) ? messages.filter(Boolean) : [];
      if (!list.length) return false;
      this.ttsQueue = this.ttsQueue.concat(list);
      if (this.ttsSpeaking) return true;
      this.ttsSpeaking = true;
      this.speakNext();
      return true;
    },
    speakNext() {
      if (typeof window === "undefined" || !window.speechSynthesis) {
        this.ttsSpeaking = false;
        this.ttsQueue = [];
        return;
      }
      const text = this.ttsQueue.shift();
      if (!text) {
        this.ttsSpeaking = false;
        return;
      }
      try {
        const utter = new SpeechSynthesisUtterance(text);
        utter.lang = this.ttsLang;
        utter.rate = this.ttsRate;
        utter.pitch = this.ttsPitch;
        utter.onend = () => this.speakNext();
        utter.onerror = () => this.speakNext();
        window.speechSynthesis.speak(utter);
      } catch (e) {
        this.speakNext();
      }
    },
    stopTts() {
      if (typeof window === "undefined") return;
      if (!window.speechSynthesis) return;
      try {
        window.speechSynthesis.cancel();
      } catch (e) {
        return;
      } finally {
        this.ttsQueue = [];
        this.ttsSpeaking = false;
      }
    },
    getData() {
      if (this.fetching) return;
      this.fetching = true;
      getTheoryexaminationQueue()
          .then((res) => {
            if (res && res.state) {
              const rows = Array.isArray(res.data) ? res.data : [];
              const signature = this.stableStringify(rows);
              if (signature !== this.lastDataSignature) {
                const hasPrev = !!this.lastDataSignature;
                const prevRows = this.lastRowsForDiff;
                this.lastDataSignature = signature;
                this.examRows = rows;
                this.lastRowsForDiff = rows;
                if (hasPrev) {
                  const messages = this.buildAnnouncements(prevRows, rows);
                  if (messages.length) this.speakMessages(messages);
                }
                this.$nextTick(() => {
                  this.startAutoScroll();
                  this.refreshMarqueeTracks();
                  const now = performance.now();
                  this.marqueeBaseTime = now;
                  this.updateMarqueeTransforms(now);
                });
              }
            }
          })
          .catch(() => {
            return;
          })
          .then(() => {
            this.fetching = false;
          });
    },
    startPolling() {
      this.stopPolling();
      this.pollTimerId = setInterval(() => {
        this.getData();
      }, this.pollIntervalMs);
    },
    stopPolling() {
      if (this.pollTimerId) clearInterval(this.pollTimerId);
      this.pollTimerId = null;
    },
    joinText(list) {
      if (!Array.isArray(list)) return "";
      return list.join("  ");
    },
    testingText(list) {
      if (!Array.isArray(list) || list.length === 0) return "未开始";
      return list.join("  ");
    },
    needsMarquee(text, type) {
      if (!text) return false;
      const thresholds = {
        testing: 12,
        waiting: 14,
        passed: 14,
      };
      return text.length > (thresholds[type] || 14);
    },
    marqueeCycle(text, type) {
      return this.needsMarquee(text, type) ? 0 : 0;
    },
    refreshMarqueeTracks() {
      if (!this.$el) {
        this._marqueeTracks = [];
        return;
      }
      this._marqueeTracks = Array.from(
          this.$el.querySelectorAll(".marquee-track")
      );
    },
    resolveTrackCycle(track) {
      const firstItem = track.querySelector(".marquee-item");
      if (!firstItem) return 0;
      const cycle = Math.round(firstItem.offsetWidth || 0);
      if (!cycle) return 0;
      track.dataset.marqueeCycle = String(cycle);
      return cycle;
    },
    updateMarqueeTransforms(now) {
      if (!this.$el) return;
      const elapsedSec = Math.max(0, (now - this.marqueeBaseTime) / 1000);
      if (!Array.isArray(this._marqueeTracks) || !this._marqueeTracks.length) {
        this.refreshMarqueeTracks();
      }
      this._marqueeTracks.forEach((track) => {
        if (!track || !track.isConnected) return;
        if (track.dataset.marqueeEnabled !== "1") {
          track.style.transform = "translate3d(0, 0, 0)";
          return;
        }
        const cycle =
            Number(track.dataset.marqueeCycle || 0) ||
            this.resolveTrackCycle(track);
        if (!cycle) {
          track.style.transform = "translate3d(0, 0, 0)";
          return;
        }
        const offset = (elapsedSec * this.marqueeSpeed) % cycle;
        track.style.transform = `translate3d(-${offset}px, 0, 0)`;
      });
    },
    startFrameLoop() {
      this.stopFrameLoop();
      this.lastFrameTime = performance.now();
      this.marqueeBaseTime = this.lastFrameTime;
      const step = (t) => {
        this.lastFrameTime = t;
        this.tickAutoScroll(t);
        this.updateMarqueeTransforms(t);
        this.frameRafId = requestAnimationFrame(step);
      };
      this.frameRafId = requestAnimationFrame(step);
    },
    stopFrameLoop() {
      if (this.frameRafId) cancelAnimationFrame(this.frameRafId);
      this.frameRafId = null;
    },
    tickAutoScroll(now) {
      if (this.examRows.length <= this.visibleRowCount) {
        this.scrollRowIndex = 0;
        this.scrollProgress = 0;
        this.vScrollMode = "";
        return;
      }

      if (!this.vScrollMode) {
        this.vScrollMode = "hold";
        this.vScrollPhaseStart = now;
        this.scrollProgress = 0;
        return;
      }

      if (this.vScrollMode === "hold") {
        if (now - this.vScrollPhaseStart >= this.vHoldMs) {
          this.vScrollMode = "move";
          this.vScrollPhaseStart = now;
        }
        return;
      }

      const progress = (now - this.vScrollPhaseStart) / this.vMoveMs;
      if (progress >= 1) {
        this.scrollProgress = 0;
        this.scrollRowIndex = (this.scrollRowIndex + 1) % this.examRows.length;
        this.vScrollMode = "hold";
        this.vScrollPhaseStart = now;
        return;
      }
      this.scrollProgress = Math.max(0, Math.min(1, progress));
    },
    updateScale() {
      const vw =
          window.innerWidth ||
          document.documentElement.clientWidth ||
          this.designWidth;
      const vh =
          window.innerHeight ||
          document.documentElement.clientHeight ||
          this.designHeight;
      const scaleX = vw / this.designWidth;
      const scaleY = vh / this.designHeight;
      const scale = Math.min(scaleX, scaleY);
      this.scale = scale > 0 ? scale : 1;
      this.offsetX = Math.max(0, (vw - this.designWidth * this.scale) / 2);
      this.offsetY = Math.max(0, (vh - this.designHeight * this.scale) / 2);
    },
    startAutoScroll() {
      this.stopAutoScroll();
      this.scrollRowIndex = 0;
      this.scrollProgress = 0;
      if (this.examRows.length <= this.visibleRowCount) {
        this.vScrollMode = "";
        return;
      }
      this.vScrollMode = "hold";
      this.vScrollPhaseStart = performance.now();
    },
    stopAutoScroll() {
      this.vScrollMode = "";
      this.scrollProgress = 0;
    },
    handleResize() {
      this.updateScale();
    },
  },
  mounted() {
    this.isTouchDevice =
        (typeof navigator !== "undefined" &&
            Number(navigator.maxTouchPoints || 0) > 0) ||
        (typeof window !== "undefined" && "ontouchstart" in window);
    this.getData();
    this.$nextTick(() => {
      this.updateScale();
      this.startAutoScroll();
      this.startFrameLoop();
      this.refreshMarqueeTracks();
      this.updateMarqueeTransforms(performance.now());
      this.startPolling();
      window.addEventListener("resize", this.handleResize);
      window.addEventListener("touchstart", this.tryUnlockAudio, {
        passive: true,
      });
      window.addEventListener("click", this.tryUnlockAudio);
    });
  },
  updated() {
    this.refreshMarqueeTracks();
    this.updateMarqueeTransforms(performance.now());
  },
  beforeDestroy() {
    this.stopPolling();
    this.stopAutoScroll();
    this.stopFrameLoop();
    this.stopTts();
    window.removeEventListener("resize", this.handleResize);
    window.removeEventListener("touchstart", this.tryUnlockAudio);
    window.removeEventListener("click", this.tryUnlockAudio);
  },
};
</script>

<style lang="scss" scoped>
:global(html),
:global(body) {
  overflow: hidden;
}

.screen-container {
  position: fixed;
  inset: 0;
  width: 100vw;
  height: 100vh;
  background: #000000;
  overflow: hidden;
}

.screen-scale {
  position: absolute;
  transform-origin: 0 0;
  background-image: url("../../assets/images/screen/bg.png");
  background-size: cover;
  background-position: center;
  font-family: "Microsoft YaHei", "PingFang SC", sans-serif;
  display: flex;
  flex-direction: column;
}

.screen-main {
  flex: 1;
  padding: 0 0 1px;
  display: flex;
  flex-direction: column;
  min-height: 0;
  overflow: hidden;
}

.screen-table-header {
  height: 110px;
  display: flex;
  background: linear-gradient(180deg, #2fafff 0%, #0061c5 100%);
}

.header-cell {
  font-weight: 500;
  font-size: 50px;
  color: #ffffff;
  display: flex;
  align-items: center;
  justify-content: center;
  line-height: 1;
}

.c0 {
  width: 13%;
}

.c1 {
  width: 17%;
}

.c2 {
  width: 9%;
}

.c3 {
  width: 18%;
}

.c4 {
  width: 24%;
}

.c5 {
  width: 22%;
}

.middle-chart {
  width: 100%;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.table-body-viewport {
  height: 100%;
  overflow: hidden;
}

.table-body-track {
  height: 100%;
  transition: transform 0s linear;
}

.table-row {
  display: flex;
  align-items: center;
  font-weight: 500;
  font-size: 42px;
  color: #1a1a1a;
  line-height: 1;
  overflow: hidden;
}

.placeholder-cell {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #8c8c8c;
}

.body-cell {
  height: 100%;
  display: flex;
  align-items: center;
  min-width: 0;
  padding: 0 16px;
  overflow: hidden;
}

.body-cell-center {
  justify-content: center;
}

.body-cell-blue {
  color: #1a74ff;
}

.body-cell-dark {
  color: #1b1e21;
}

.body-cell-passed {
  color: #1b1e21;
}

.text-ellipsis {
  min-width: 0;
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}

.passed-prefix {
  flex: 0 0 auto;
  color: #ff7f3f;
  margin-right: 18px;
}

.passed-users {
  flex: 1;
  min-width: 0;
}

.marquee-wrap {
  width: 100%;
  min-width: 0;
  overflow: hidden;
  display: flex;
  align-items: center;
  white-space: nowrap;
}

.marquee-track {
  flex: 0 0 auto;
  display: inline-flex;
  align-items: center;
  will-change: transform;
  transform: translate3d(0, 0, 0);
  backface-visibility: hidden;
}

.body-cell.c3 .marquee-track[data-marquee-enabled="0"],
.body-cell.c4 .marquee-track[data-marquee-enabled="0"] {
  margin: 0 auto;
}

.marquee-item {
  flex: 0 0 auto;
  padding-right: 80px;
}

.text-danger {
  color: #ff2d2d;
}

.text-success {
  color: #15be75;
}

.screen-footer {
  height: 86px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #0287ff;
  font-weight: 500;
  font-size: 44px;
  line-height: 1;
  letter-spacing: 1px;
}

.tip-label {
  color: #ffffff;
  margin-right: 12px;
}

.tip-text {
  color: #ffe600;
}

.sound-unlock-mask {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.35);
  z-index: 10;
}

.sound-unlock-card {
  width: 780px;
  max-width: 92vw;
